import React, { useEffect, useState } from 'react';
import { get, put } from '../api';

const AddressesList = () => {
  const [addresses, setAddresses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [phoneValue, setPhoneValue] = useState('');
  const [addressValue, setAddressValue] = useState('');
  const [actionError, setActionError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);

  const loadAddresses = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await get('/api/admin-lists/addresses');
      setAddresses(response.data);
    } catch (err) {
      console.error(err);
      setError('Unable to load addresses.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAddresses();
  }, []);

  const handleRefresh = () => {
    loadAddresses();
  };

  const handleEdit = (address) => {
    setEditingId(address.id);
    setPhoneValue(address.phone || '');
    setAddressValue(address.savedAddress || '');
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleSave = async () => {
    if (!editingId) return;
    setActionError(null);
    setSuccessMessage(null);

    try {
      await put(`/api/admin-lists/addresses/${editingId}`, {
        phone: phoneValue,
        address: addressValue,
      });
      setSuccessMessage('Saved successfully.');
      setEditingId(null);
      setPhoneValue('');
      setAddressValue('');
      await loadAddresses();
    } catch (err) {
      console.error(err);
      setActionError('Unable to update details.');
    }
  };

  return (
    <div>
      <h2>Delivery Address Master</h2>
      <div style={{ marginBottom: 12 }}>
        <button onClick={handleRefresh} disabled={loading}>
          Refresh
        </button>
      </div>
      {loading && <p>Loading addresses...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {successMessage && <p style={{ color: 'green' }}>{successMessage}</p>}
      {actionError && <p style={{ color: 'red' }}>{actionError}</p>}

      {!loading && !error && (
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Parent ID</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Phone</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Saved Address</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {addresses.map((address) => (
              <tr key={address.id}>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.id}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.phone}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.savedAddress || 'None'}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <button onClick={() => handleEdit(address)}>Edit</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {editingId && (
        <div style={{ marginTop: 24, maxWidth: 600 }}>
          <h3>Edit Parent #{editingId}</h3>
          <div style={{ marginBottom: 8 }}>
            <label style={{ display: 'block', marginBottom: 4 }}>Phone</label>
            <input
              type="text"
              value={phoneValue}
              onChange={(e) => setPhoneValue(e.target.value)}
              style={{ width: '100%', padding: 8, marginBottom: 12 }}
            />
            <label style={{ display: 'block', marginBottom: 4 }}>Saved Address</label>
            <textarea
              value={addressValue}
              onChange={(e) => setAddressValue(e.target.value)}
              rows={4}
              style={{ width: '100%', padding: 8 }}
            />
          </div>
          <button onClick={handleSave} style={{ marginRight: 8 }}>
            Save
          </button>
          <button
            onClick={() => {
              setEditingId(null);
              setPhoneValue('');
              setAddressValue('');
            }}
          >
            Cancel
          </button>
        </div>
      )}
    </div>
  );
};

export default AddressesList;
